134	    '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 18 18">' +
135	      '<path fill="#EA4335" d="M9 7.364v3.534h4.914c-.216 1.136-.864 2.098-1.836 2.745l2.966 2.302c1.728-1.593 2.726-3.939 2.726-6.727 0-.648-.058-1.271-.165-1.854H9z"/>' +
136	      '<path fill="#34A853" d="M9 18c2.43 0 4.468-.806 5.958-2.182l-2.966-2.302c-.823.552-1.875.879-2.992.879-2.298 0-4.244-1.55-4.94-3.633H.994v2.375A8.997 8.997 0 0 0 9 18z"/>' +
137	      '<path fill="#4A90E2" d="M4.06 10.762A5.41 5.41 0 0 1 3.784 9c0-.612.106-1.206.276-1.762V4.863H.994A8.997 8.997 0 0 0 0 9c0 1.452.347 2.827.994 4.137l3.066-2.375z"/>' +
138	      '<path fill="#FBBC05" d="M9 3.605c1.321 0 2.507.454 3.441 1.345l2.581-2.582C13.463.918 11.425 0 9 0A8.997 8.997 0 0 0 .994 4.863L4.06 7.238C4.756 5.155 6.702 3.605 9 3.605z"/>' +
