142	  function styleGoogleButton(button) {
143	    if (!button || button.dataset.hiclawGoogleStyled === "1") return;
144	    button.dataset.hiclawGoogleStyled = "1";
145	    button.style.background = "#ffffff";
146	    button.style.color = "#1f1f1f";
147	    button.style.border = "1px solid #dadce0";
148	    button.style.borderRadius = "999px";
149	    button.style.boxShadow = "0 1px 2px rgba(16,24,40,0.08)";
150	    button.style.fontWeight = "600";
151	    button.style.minHeight = "44px";
152	    button.style.padding = "10px 18px";
153	    button.style.display = "inline-flex";
154	    button.style.alignItems = "center";
155	    button.style.justifyContent = "center";
156	    button.style.gap = "12px";
157	    button.style.fontFamily = "Arial, sans-serif";
158	
159	    var text = normalize(button.textContent);
160	    if (!/google/.test(text)) {
161	      button.textContent = "Continue with Google";
162	    }
163	
164	    if (!button.querySelector(".hiclaw-google-mark")) {
165	      var icon = document.createElement("span");
166	      icon.className = "hiclaw-google-mark";
167	      icon.setAttribute("aria-hidden", "true");
168	      icon.style.width = "18px";
169	      icon.style.height = "18px";
170	      icon.style.display = "inline-block";
171	      icon.style.flex = "0 0 18px";
172	      icon.style.backgroundImage = 'url("' + googleIcon + '")';
173	      icon.style.backgroundRepeat = "no-repeat";
174	      icon.style.backgroundPosition = "center";
175	      icon.style.backgroundSize = "18px 18px";
