180	
181	      button.textContent = "";
182	      button.appendChild(icon);
183	      button.appendChild(label);
184	    }
185	  }
186	
187	  function findGoogleButtons() {
188	    Array.from(document.querySelectorAll("button, a[role='button'], a")).forEach(function(el) {
189	      var text = normalize(el.textContent);
190	      if (GOOGLE_LABELS.indexOf(text) !== -1) {
191	        styleGoogleButton(el);
192	      }
193	    });
194	  }
195	
196	  var skipVerificationLastClick = 0;
197	
198	  function autoSkipVerification() {
199	    var bodyText = normalize(document.body && document.body.textContent);
200	    if (!bodyText) return;
201	    if (bodyText.indexOf("verify this device to set up secure messaging") === -1 &&
202	        bodyText.indexOf("confirm your identity") === -1) {
203	      return;
204	    }
205	
206	    // Cooldown: at most one click every 2 seconds to prevent observer loop freeze.
207	    var now = Date.now();
208	    if (now - skipVerificationLastClick < 2000) return;
209	
210	    var buttons = Array.from(document.querySelectorAll("button, a[role='button'], a"));
211	    for (var i = 0; i < buttons.length; i++) {
212	      var text = normalize(buttons[i].textContent);
213	      if (SKIP_LABELS.indexOf(text) !== -1) {
214	        skipVerificationLastClick = now;
215	        buttons[i].click();
216	        return;
217	      }
218	    }
219	  }
220	
221	  function run() {
222	    findGoogleButtons();
223	    autoSkipVerification();
224	  }
225	
226	  var observer = new MutationObserver(run);
227	  observer.observe(document.documentElement, { childList: true, subtree: true });
228	
229	  if (document.readyState === "loading") {
230	    document.addEventListener("DOMContentLoaded", run);
231	  } else {
232	    run();
233	  }
234	})();
