237	cat > /opt/element-web/new-chat-btn.js << 'EOF'
238	(function() {
239	  var ID = "hiclaw-new-chat-btn";
240	  var ROOM_PREFIX = "Chat: ";
241	  var busy = false;
242	
243	  function setState(btn, label, disabled) {
244	    btn.textContent = label;
245	    btn.style.opacity = disabled ? "0.7" : "1";
246	    btn.style.cursor = disabled ? "wait" : "pointer";
247	  }
248	
249	  function focusNewRoom(roomName) {
250	    var deadline = Date.now() + 20000;
251	    function tryFocus() {
252	      var walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT);
253	      var node;
254	      while ((node = walker.nextNode())) {
255	        var text = (node.nodeValue || "").trim();
256	        if (text !== roomName) continue;
257	        var el = node.parentElement;
258	        while (el && el !== document.body) {
259	          var role = el.getAttribute && el.getAttribute("role");
260	          if (el.tagName === "A" || el.tagName === "BUTTON" || role === "treeitem" || role === "button") {
261	            el.click();
262	            return true;
263	          }
264	          el = el.parentElement;
265	        }
266	      }
267	      return false;
268	    }
269	
270	    if (tryFocus()) return;
271	    var timer = setInterval(function() {
272	      if (tryFocus()) {
273	        clearInterval(timer);
274	        return;
275	      }
276	      if (Date.now() > deadline) {
277	        clearInterval(timer);
278	        window.alert("New chat created. If it did not open automatically, it should now be visible in the room list.");
279	      }
280	    }, 750);
281	  }
282	
283	  async function createRoom(btn) {
284	    if (busy) return;
285	    var raw = window.prompt("Name the new chat", "");
286	    if (raw === null) return;
287	    var name = raw.trim();
288	    if (!name) {
289	      window.alert("Please enter a chat name.");
290	      return;
291	    }
292	
293	    busy = true;
294	    setState(btn, "Creating chat...", true);
295	    try {
296	      var res = await window.fetch("/hiclaw-api/new-chat", {
297	        method: "POST",
298	        headers: { "Content-Type": "application/json" },
299	        body: JSON.stringify({ name: name })
300	      });
301	      var body = await res.json().catch(function() { return {}; });
302	      if (!res.ok) {
303	        throw new Error(body.error || ("Request failed (" + res.status + ")"));
304	      }
305	      focusNewRoom(body.room_name || (ROOM_PREFIX + name));
306	    } catch (err) {
307	      window.alert("Could not create the new chat: " + (err && err.message ? err.message : String(err)));
308	    } finally {
309	      busy = false;
310	      setState(btn, "+ New Chat", false);
311	    }
312	  }
313	
314	  function inject() {
315	    if (document.getElementById(ID)) return;
316	    if (!document.body) return;
317	    var btn = document.createElement("button");
318	    btn.id = ID;
319	    btn.type = "button";
320	    btn.title = "Create a new HiClaw chat room";
321	    btn.textContent = "+ New Chat";
322	    btn.style.cssText = "position:fixed;left:70px;bottom:56px;width:232px;z-index:9001;padding:8px 14px;background:#155eef;color:#fff;border:0;border-radius:8px;font-family:system-ui,-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif;font-size:13px;font-weight:700;text-align:center;box-shadow:0 1px 8px rgba(0,0,0,0.35);pointer-events:auto;";
323	    btn.addEventListener("click", function() { createRoom(btn); });
324	    document.body.appendChild(btn);
325	  }
326	
327	  if (document.readyState === "loading") {
328	    document.addEventListener("DOMContentLoaded", function() { setTimeout(inject, 500); });
329	  } else {
330	    setTimeout(inject, 500);
331	  }
332	})();
333	EOF
