726	# or wrapper-script changes. If we start a second nginx instance, element-web enters
727	# a crash loop and the HiClaw chat UI appears disconnected even though the manager is
728	# still processing messages. Always clear any existing nginx master before starting
729	# the foreground instance that supervisord expects to own.
730	if pgrep -x nginx >/dev/null 2>&1; then
