740	    pkill -f /opt/element-web/hiclaw-chat-api.py 2>/dev/null || true
741	    for _ in 1 2 3 4 5; do
742	        pgrep -f /opt/element-web/hiclaw-chat-api.py >/dev/null 2>&1 || break
743	        sleep 1
744	    done
