(function () {
  'use strict';

  /* NY Knicks logo as inline SVG data URI */
  var KNICKS_URI = 'data:image/svg+xml;utf8,' + encodeURIComponent(
    '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100">' +
    '<circle cx="50" cy="50" r="50" fill="#F58426"/>' +
    '<circle cx="50" cy="50" r="43" fill="#006BB6"/>' +
    '<text x="50" y="43" text-anchor="middle" fill="white"' +
    ' font-family="Arial,sans-serif" font-weight="900" font-size="13" letter-spacing="0.5">NEW YORK</text>' +
    '<text x="50" y="64" text-anchor="middle" fill="#F58426"' +
    ' font-family="Arial,sans-serif" font-weight="900" font-size="20" letter-spacing="0.5">KNICKS</text>' +
    '</svg>'
  );

  /* Set a CSS property at !important priority via inline style */
  function sp(el, prop, val) { el.style.setProperty(prop, val, 'important'); }

  /* Replace "admin"→"Albert" and "manager"→"Penny" in text nodes */
  function renameText(el) {
    if (!el || el.dataset.hiclawR) return;
    el.dataset.hiclawR = '1';
    var walker = document.createTreeWalker(el, NodeFilter.SHOW_TEXT, null, false);
    var node;
    while ((node = walker.nextNode())) {
      var v = node.nodeValue;
      if (!v) continue;
      var u = v.replace(/\badmin\b/gi, 'Albert').replace(/\bmanager\b/gi, 'Penny');
      if (u !== v) node.nodeValue = u;
    }
  }

  /* Style a single event tile */
  function styleTile(tile) {
    if (tile.dataset.hiclawT) return;
    tile.dataset.hiclawT = '1';

    /* Skip system/info rows */
    if (tile.classList.contains('mx_EventTile_info')) return;

    var own = tile.classList.contains('mx_EventTile_own');
    tile.classList.add(own ? 'hiclaw-own' : 'hiclaw-other');

    /*
     * Convert the tile from flex to block so float works on the line child.
     * Inline !important overrides even Element Web's own !important rules.
     */
    sp(tile, 'display', 'block');
    sp(tile, 'overflow', 'hidden');
    sp(tile, 'background', 'transparent');
    sp(tile, 'padding', '2px 12px');
    sp(tile, 'margin', '1px 0');
    sp(tile, 'clear', 'both');

    /* Float the message line left or right */
    var line = tile.querySelector('.mx_EventTile_line');
    if (line) {
      sp(line, 'float', own ? 'right' : 'left');
      sp(line, 'max-width', '72%');
      sp(line, 'clear', 'none');
      sp(line, 'background', 'transparent');
      sp(line, 'box-shadow', 'none');
    }

    /* Sender name: rename + Knicks icon for Albert */
    var sender = tile.querySelector(
      '.mx_SenderProfile, [class*="SenderProfile"], [class*="senderDetails"]'
    );
    if (sender) {
      renameText(sender);
      if (own) {
        sp(sender, 'text-align', 'right');
        sp(sender, 'font-size', '11px');
        sp(sender, 'opacity', '0.75');
        /* Inject the Knicks logo before the name text */
        if (!sender.querySelector('.hiclaw-knicks')) {
          var icon = document.createElement('img');
          icon.className = 'hiclaw-knicks';
          icon.src = KNICKS_URI;
          icon.alt = '';
          icon.style.cssText =
            'width:14px;height:14px;border-radius:50%;vertical-align:middle;' +
            'margin-right:4px;display:inline-block;flex-shrink:0;';
          sender.insertBefore(icon, sender.firstChild);
        }
      } else {
        sp(sender, 'font-size', '11px');
        sp(sender, 'opacity', '0.75');
        sp(sender, 'color', '#2db14e');
      }
    }

    /* Clearfix so the tile height contains the floated line */
    if (!tile.querySelector('.hiclaw-cf')) {
      var cf = document.createElement('div');
      cf.className = 'hiclaw-cf';
      cf.style.cssText = 'clear:both;display:block;height:0;line-height:0;font-size:0;';
      tile.appendChild(cf);
    }
  }

  /* Rename names that appear outside message tiles (member list, header, etc.) */
  function renameGlobal() {
    var sel = [
      '.mx_RoomHeader [class*="name"]',
      '.mx_EntityTile [class*="name"]',
      '.mx_RoomTile_name',
      '[class*="MemberInfo"] [class*="name"]',
      '[class*="UserInfo"] [class*="name"]',
      '[class*="displayName"]',
      '[class*="ProfileHeader"] [class*="name"]'
    ].join(',');
    document.querySelectorAll(sel).forEach(renameText);
  }

  function run() {
    document.querySelectorAll('.mx_EventTile:not([data-hiclaw-t])').forEach(styleTile);
    renameGlobal();
  }

  var obs = new MutationObserver(run);

  function init() {
    run();
    obs.observe(document.documentElement, { childList: true, subtree: true });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', function () { setTimeout(init, 800); });
  } else {
    setTimeout(init, 800);
  }
})();
EOF

