1	// chat-style.js — HiClaw chat readability fix for Element Web
2	// Written with NO single quotes anywhere, so it drops cleanly into BOTH:
3	//   - start-element-web.sh   : cat > /opt/element-web/chat-style.js << "EOF"
4	//   - fix-element-config.sh  : docker exec ... bash -c "cat > ... << EOF ... EOF"
5	//
6	// What it fixes:
7	//   - Your messages (@admin) align RIGHT; the HiClaw Manager (@manager) aligns LEFT.
8	//   - Two distinct, soft, readable bubble colors instead of one bold shared color.
9	//   - Sender name sits consistently above the first bubble, on that speaker's side.
10	//
11	// Pure CSS (no DOM rewriting), so it survives Element upgrades while it stays injected.
12	(function () {
13	  var ID = "hiclaw-chat-style";
14	  if (document.getElementById(ID)) return;
15	
16	  // CSS kept in a backtick template literal: no single OR unescaped double quotes
17	  // leak into the surrounding shell heredoc.
18	  var css = `
19	    .mx_EventTile[data-layout="bubble"] { --eventbubble-self-bg: #e4edff; }
20	
21	    /* Bubble base */
22	    .mx_EventTile[data-layout="bubble"] .mx_EventTile_line .mx_MTextBody,
23	    .mx_EventTile[data-layout="bubble"] .mx_EventTile_line {
24	      border-radius: 16px !important;
25	      font-size: 14.5px !important;
26	      line-height: 1.5 !important;
27	    }
28	
29	    /* Other speakers (HiClaw Manager) -> LEFT, soft neutral */
