69	  function focusNewRoom(roomName) {
70	    var deadline = Date.now() + 20000;
71	    function tryFocus() {
72	      var walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT);
73	      var node;
74	      while ((node = walker.nextNode())) {
75	        var text = (node.nodeValue || "").trim();
76	        if (text !== roomName) continue;
77	        var el = node.parentElement;
78	        while (el && el !== document.body) {
79	          var role = el.getAttribute && el.getAttribute("role");
80	          if (el.tagName === "A" || el.tagName === "BUTTON" || role === "treeitem" || role === "button") {
81	            el.click();
82	            return true;
83	          }
84	          el = el.parentElement;
85	        }
86	      }
87	      return false;
88	    }
