155	docker exec hiclaw-controller bash -c 'cat > /opt/element-web/hiclaw-chat-api.py << '"'"'EOF'"'"'
156	#!/usr/bin/env python3
157	import json
158	import os
159	import sys
160	import time
161	import urllib.error
162	import urllib.parse
163	import urllib.request
164	from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer
165	
166	MATRIX_URL = os.environ.get("HICLAW_MATRIX_URL", "http://hiclaw-controller:6167").rstrip("/")
167	MATRIX_DOMAIN = os.environ.get("HICLAW_MATRIX_DOMAIN", "matrix-local.hiclaw.io:18080")
168	ADMIN_USER = os.environ.get("HICLAW_ADMIN_USER", "admin")
169	ADMIN_PASSWORD = os.environ.get("HICLAW_ADMIN_PASSWORD", "")
170	MANAGER_USER = os.environ.get("HICLAW_MANAGER_USER", "manager")
171	ADMIN_FULL_ID = f"@{ADMIN_USER}:{MATRIX_DOMAIN}"
172	MANAGER_FULL_ID = f"@{MANAGER_USER}:{MATRIX_DOMAIN}"
173	ROOM_PREFIX = "Chat: "
174	
175	def fail(message, code=500):
176	    raise RuntimeError(f"{code}:{message}")
177	
178	def matrix_request(method, path, payload=None, token=None):
179	    url = f"{MATRIX_URL}{path}"
180	    data = None
181	    headers = {"Content-Type": "application/json"}
182	    if token:
183	        headers["Authorization"] = f"Bearer {token}"
184	    if payload is not None:
185	        data = json.dumps(payload).encode("utf-8")
186	    req = urllib.request.Request(url, data=data, headers=headers, method=method)
187	    try:
188	        with urllib.request.urlopen(req, timeout=20) as resp:
189	            raw = resp.read().decode("utf-8")
190	            return resp.status, json.loads(raw) if raw else {}
191	    except urllib.error.HTTPError as exc:
192	        raw = exc.read().decode("utf-8", "ignore")
193	        try:
194	            body = json.loads(raw) if raw else {}
195	        except Exception:
196	            body = {"error": raw or exc.reason}
197	        return exc.code, body
198	
199	def login():
200	    if not ADMIN_PASSWORD:
201	        fail("HICLAW_ADMIN_PASSWORD is not available inside hiclaw-controller")
202	    status, body = matrix_request(
203	        "POST",
204	        "/_matrix/client/v3/login",
205	        {
206	            "type": "m.login.password",
207	            "identifier": {"type": "m.id.user", "user": ADMIN_USER},
208	            "password": ADMIN_PASSWORD,
209	        },
210	    )
211	    token = body.get("access_token")
212	    if status != 200 or not token:
213	        fail(f"admin login failed: {body.get('error', body)}", 502)
214	    return token
215	
216	def create_room(token, title):
217	    safe = " ".join(title.split()).strip()
218	    if not safe:
219	        fail("chat name cannot be empty", 400)
220	    if len(safe) > 80:
221	        safe = safe[:80].rstrip()
222	    room_name = f"{ROOM_PREFIX}{safe}"
223	    status, body = matrix_request(
224	        "POST",
225	        "/_matrix/client/v3/createRoom",
226	        {
227	            "name": room_name,
228	            "topic": f"Separate HiClaw conversation: {safe}",
229	            "invite": [MANAGER_FULL_ID],
230	            "preset": "trusted_private_chat",
231	            "power_level_content_override": {
232	                "users": {
233	                    ADMIN_FULL_ID: 100,
234	                    MANAGER_FULL_ID: 100
235	                }
236	            }
237	        },
238	        token=token,
239	    )
240	    room_id = body.get("room_id")
241	    if status not in (200, 201) or not room_id:
242	        fail(f"room creation failed: {body.get('error', body)}", 502)
243	
244	    txn = f"new-chat-{int(time.time())}"
245	    msg_status, msg_body = matrix_request(
246	        "PUT",
247	        f"/_matrix/client/v3/rooms/{urllib.parse.quote(room_id, safe='')}/send/m.room.message/{txn}",
248	        {
249	            "msgtype": "m.text",
250	            "body": f'{MANAGER_FULL_ID} This is a separate admin chat named "{safe}". Treat this room as an isolated conversation thread and keep replies in this room.',
251	            "m.mentions": {"user_ids": [MANAGER_FULL_ID]},
252	        },
253	        token=token,
254	    )
255	    if msg_status not in (200, 201) or "event_id" not in msg_body:
256	        fail(f"initial message failed: {msg_body.get('error', msg_body)}", 502)
257	
258	    return {"room_id": room_id, "room_name": room_name, "event_id": msg_body["event_id"]}
259	
260	class Handler(BaseHTTPRequestHandler):
261	    def _send(self, status, payload):
262	        body = json.dumps(payload).encode("utf-8")
263	        self.send_response(status)
264	        self.send_header("Content-Type", "application/json")
265	        self.send_header("Cache-Control", "no-store")
266	        self.send_header("Content-Length", str(len(body)))
267	        self.end_headers()
268	        self.wfile.write(body)
269	
270	    def do_GET(self):
271	        if self.path == "/healthz":
272	            self._send(200, {"ok": True})
273	            return
274	        self._send(404, {"error": "not found"})
275	
276	    def do_POST(self):
277	        if self.path != "/new-chat":
278	            self._send(404, {"error": "not found"})
279	            return
280	        try:
281	            length = int(self.headers.get("Content-Length", "0"))
282	            raw = self.rfile.read(length).decode("utf-8") if length else "{}"
283	            payload = json.loads(raw) if raw else {}
284	            title = str(payload.get("name", "")).strip()
285	            if payload.get("dry_run"):
286	                self._send(200, {"ok": True, "room_name": f"{ROOM_PREFIX}{title}"})
287	                return
288	            token = login()
289	            self._send(200, create_room(token, title))
290	        except RuntimeError as exc:
291	            code_text, _, message = str(exc).partition(":")
292	            try:
293	                code = int(code_text)
294	            except ValueError:
295	                code = 500
296	                message = str(exc)
297	            self._send(code, {"error": message})
298	        except Exception as exc:
299	            self._send(500, {"error": str(exc)})
300	
301	    def log_message(self, fmt, *args):
302	        sys.stdout.write("[hiclaw-chat-api] " + (fmt % args) + "\n")
303	        sys.stdout.flush()
304	
305	if __name__ == "__main__":
306	    ThreadingHTTPServer(("127.0.0.1", 8091), Handler).serve_forever()
307	EOF
