358	# Install the npm wrapper in hiclaw-manager so "Update now" button works.
359	# The wrapper copies HiClaw-specific extensions after npm installs a new openclaw,
360	# then updates the /usr/local/bin/openclaw symlink so the container restart picks up the new version.
361	docker exec hiclaw-manager bash -c 'cat > /usr/local/bin/npm << '"'"'WRAPEOF'"'"'
362	#!/bin/bash
363	# HiClaw npm wrapper: patches openclaw installs with HiClaw-specific extensions.
364	/usr/lib/node_modules/npm/bin/npm-cli.js "$@"
365	EXIT_CODE=$?
366	
367	if [ $EXIT_CODE -eq 0 ] && ([[ "$1" == "install" ]] || [[ "$1" == "i" ]]) && echo "$@" | grep -qE "\-g|--global" && echo "$@" | grep -q "openclaw"; then
368	    NEW_ROOT="/usr/lib/node_modules/openclaw"
369	    OLD_ROOT="/opt/openclaw"
370	    if [ -d "$NEW_ROOT/dist/extensions" ] && [ -d "$OLD_ROOT/dist/extensions" ]; then
371	        for ext_dir in "$OLD_ROOT/dist/extensions"/*/; do
372	            ext=$(basename "$ext_dir")
373	            [ ! -d "$NEW_ROOT/dist/extensions/$ext" ] && cp -r "$ext_dir" "$NEW_ROOT/dist/extensions/"
374	        done
375	        ln -sf "$NEW_ROOT/openclaw.mjs" /usr/local/bin/openclaw
376	    fi
377	fi
378	
379	exit $EXIT_CODE
380	WRAPEOF
381	chmod +x /usr/local/bin/npm
382	ln -sf /usr/local/bin/npm /usr/bin/npm'
383	
384	echo "hiclaw-manager npm wrapper installed → Update now button will work"
385	
386	# Install the mc wrapper + inject script in hiclaw-manager so MCP config survives
387	# gateway restarts and MinIO sync cycles that strip unknown keys.
