#!/usr/bin/env python3
import json, sys, os

path = sys.argv[1]
mcp_cfg = {
    "servers": {
        "browser": {
            "command": "npx",
            "args": ["@playwright/mcp", "--cdp-endpoint", "http://10.0.5.4:9223"],
            "type": "stdio"
        }
    }
}

def inject(p):
    if not os.path.isfile(p):
        return
    try:
        d = json.load(open(p))
        if d.get("mcp") != mcp_cfg:
            d["mcp"] = mcp_cfg
            json.dump(d, open(p, "w"), indent=2)
    except Exception:
        pass

try:
    inject(path)
    bak = os.path.join(os.path.dirname(path), ".openclaw", "openclaw.json.bak")
    inject(bak)
except Exception:
    pass
PYEOF
