                esac
                ;;
        esac
    done

elif [[ "$1" == "mirror" ]]; then
    SRC="" DEST=""
    for arg in "${@:2}"; do
        [[ "$arg" == --* ]] && continue
        [ -z "$SRC" ] && { SRC="$arg"; continue; }
        [ -z "$DEST" ] && { DEST="$arg"; break; }
    done

