// chat-style.js — HiClaw chat readability fix for Element Web
// Written with NO single quotes anywhere, so it drops cleanly into BOTH:
//   - start-element-web.sh   : cat > /opt/element-web/chat-style.js << "EOF"
//   - fix-element-config.sh  : docker exec ... bash -c "cat > ... << EOF ... EOF"
//
// What it fixes:
//   - Your messages (@admin) align RIGHT; the HiClaw Manager (@manager) aligns LEFT.
//   - Two distinct, soft, readable bubble colors instead of one bold shared color.
//   - Sender name sits consistently above the first bubble, on that speaker's side.
//
// Pure CSS (no DOM rewriting), so it survives Element upgrades while it stays injected.
(function () {
  var ID = "hiclaw-chat-style";
  if (document.getElementById(ID)) return;

  // CSS kept in a backtick template literal: no single OR unescaped double quotes
  // leak into the surrounding shell heredoc.
  var css = `
    .mx_EventTile[data-layout="bubble"] { --eventbubble-self-bg: #e4edff; }

    /* Bubble base */
    .mx_EventTile[data-layout="bubble"] .mx_EventTile_line .mx_MTextBody,
    .mx_EventTile[data-layout="bubble"] .mx_EventTile_line {
      border-radius: 16px !important;
      font-size: 14.5px !important;
      line-height: 1.5 !important;
    }

    /* Other speakers (HiClaw Manager) -> LEFT, soft neutral */
    .mx_EventTile[data-layout="bubble"][data-self="false"] .mx_EventTile_line > .mx_MTextBody,
    .mx_EventTile[data-layout="bubble"][data-self="false"] .mx_EventTile_line {
      background: #f1f3f6 !important;
      border: 1px solid #e4e8ee !important;
      color: #1d232c !important;
      border-bottom-left-radius: 6px !important;
    }
    .mx_EventTile[data-layout="bubble"][data-self="false"] .mx_DisambiguatedProfile,
    .mx_EventTile[data-layout="bubble"][data-self="false"] .mx_SenderProfile {
      color: #0a8f6a !important;
      font-weight: 700 !important;
      text-align: left !important;
    }

    /* You (@admin) -> RIGHT, soft blue */
    .mx_EventTile[data-layout="bubble"][data-self="true"] .mx_EventTile_line > .mx_MTextBody,
    .mx_EventTile[data-layout="bubble"][data-self="true"] .mx_EventTile_line {
      background: #e4edff !important;
      border: 1px solid #ccddff !important;
      color: #15233b !important;
      border-bottom-right-radius: 6px !important;
    }
    .mx_EventTile[data-layout="bubble"][data-self="true"] .mx_DisambiguatedProfile,
    .mx_EventTile[data-layout="bubble"][data-self="true"] .mx_SenderProfile {
      color: #2b62d6 !important;
      font-weight: 700 !important;
      text-align: right !important;
    }

    /* Keep code blocks readable on the soft fills */
    .mx_EventTile[data-layout="bubble"] .mx_EventTile_line pre {
      background: #0f1722 !important; color: #d7e2f0 !important; border: 0 !important;
    }
  `;

  function inject() {
    if (document.getElementById(ID)) return;
    if (!document.head) return;
    var s = document.createElement("style");
    s.id = ID;
    s.textContent = css;
    document.head.appendChild(s);

    // Make "bubble" the default layout so left/right alignment actually applies.
    try {
      if (!localStorage.getItem("mx_hiclaw_layout_set")) {
        var raw = localStorage.getItem("mx_local_settings");
        var obj = raw ? JSON.parse(raw) : {};
        obj.layout = "bubble";
        localStorage.setItem("mx_local_settings", JSON.stringify(obj));
        localStorage.setItem("mx_hiclaw_layout_set", "1");
      }
    } catch (e) { /* non-fatal */ }
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", inject);
  } else {
    inject();
  }
})();
EOF'

docker exec hiclaw-controller bash -c 'cat > /opt/element-web/imessage-tweaks.js << '"'"'EOF'"'"'
// imessage-tweaks.js — HiClaw name + icon tweaks only.
// Bubble layout/colors are owned by chat-style.js; this file just renames
// admin->Albert and manager->Penny and adds a NY Knicks icon next to Albert.
// Written with NO single quotes so it drops into both heredoc styles like chat-style.js.
(function () {
  "use strict";

  // NY Knicks logo as inline SVG data URI (double-quoted attrs escaped for JS string)
  var KNICKS_URI = "data:image/svg+xml;utf8," + encodeURIComponent(
    "<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 100 100\">" +
    "<circle cx=\"50\" cy=\"50\" r=\"50\" fill=\"#F58426\"/>" +
    "<circle cx=\"50\" cy=\"50\" r=\"43\" fill=\"#006BB6\"/>" +
    "<text x=\"50\" y=\"43\" text-anchor=\"middle\" fill=\"white\" font-family=\"Arial\" font-weight=\"900\" font-size=\"13\">NEW YORK</text>" +
    "<text x=\"50\" y=\"64\" text-anchor=\"middle\" fill=\"#F58426\" font-family=\"Arial\" font-weight=\"900\" font-size=\"20\">KNICKS</text>" +
    "</svg>"
  );

  // Replace admin->Albert and manager->Penny in the text nodes under el.
  function renameText(el) {
    if (!el || el.dataset.hiclawR) return;
    el.dataset.hiclawR = "1";
    var walker = document.createTreeWalker(el, NodeFilter.SHOW_TEXT, null, false);
    var node;
    while ((node = walker.nextNode())) {
      var v = node.nodeValue;
      if (!v) continue;
      var u = v.replace(/\badmin\b/gi, "Albert").replace(/\bmanager\b/gi, "Penny");
      if (u !== v) node.nodeValue = u;
    }
  }

  // Per-tile: rename the sender name, and prepend the Knicks icon for own messages.
  function processTile(tile) {
    if (tile.dataset.hiclawT) return;
    tile.dataset.hiclawT = "1";
    if (tile.classList.contains("mx_EventTile_info")) return;

    var own = tile.classList.contains("mx_EventTile_own");
    var sender = tile.querySelector(
      ".mx_SenderProfile, [class*=\"SenderProfile\"], [class*=\"DisambiguatedProfile\"]"
    );
    if (!sender) return;
    renameText(sender);

    if (own && !sender.querySelector(".hiclaw-knicks")) {
      var icon = document.createElement("img");
      icon.className = "hiclaw-knicks";
      icon.src = KNICKS_URI;
      icon.alt = "";
      icon.style.cssText =
        "width:14px;height:14px;border-radius:50%;vertical-align:middle;" +
        "margin-right:4px;display:inline-block;";
      sender.insertBefore(icon, sender.firstChild);
    }
  }

  // Rename names that appear outside message tiles (member list, header, etc.).
  function renameGlobal() {
    var sel = [
      ".mx_RoomHeader [class*=\"name\"]",
      ".mx_EntityTile [class*=\"name\"]",
      ".mx_RoomTile_name",
      "[class*=\"MemberInfo\"] [class*=\"name\"]",
      "[class*=\"UserInfo\"] [class*=\"name\"]",
      "[class*=\"displayName\"]",
      "[class*=\"DisambiguatedProfile\"]"
    ].join(",");
    document.querySelectorAll(sel).forEach(renameText);
  }

  function run() {
    document.querySelectorAll(".mx_EventTile:not([data-hiclaw-t])").forEach(processTile);
    renameGlobal();
  }

  var obs = new MutationObserver(run);

  function init() {
    run();
    obs.observe(document.documentElement, { childList: true, subtree: true });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", function () { setTimeout(init, 800); });
  } else {
    setTimeout(init, 800);
  }
})();
EOF'

